"use client";
import Link from "next/link";
import Image from "next/image";
import Head from "next/head";
import { useState, useEffect, useRef, useCallback } from "react";

const styles = {  // Inline styles (replace with SCSS modules in a real app)
  container: {
    display: "flex",
    minHeight: "100vh",
  },
  mainContent: {
    flex: 1,
    padding: "20px",
    transition: "margin-left 0.3s ease",
    backgroundColor: "#f0f0f0",
    boxSizing: "border-box",
  },
  activeUsersSection: {
    marginBottom: "20px",
    backgroundColor: "white",
    padding: "15px",
    borderRadius: "5px",
    boxShadow: "0 0 5px rgba(0, 0, 0, 0.1)",
  },
  sectionTitle: {
    marginBottom: "15px",
    fontSize: "1.2em",
    color: "#333",
  },
    sectionTitleSmall: {
    marginBottom: "10px",
    fontSize: "1em",
    color: "#333",
  },
  activeUsersTable: {
    width: "100%",
    borderCollapse: "collapse",
    backgroundColor: "white",
  },
  activeUsersTableTh: {
    border: "1px solid #ddd",
    padding: "8px",
    textAlign: "left",
    backgroundColor: "#e9ecef",
    fontWeight: "bold",
  },
  activeUsersTableTd: {
    border: "1px solid #ddd",
    padding: "8px",
    textAlign: "left",
  },
  discountCodeSection: {
    border: "1px solid #ced4da",
    padding: "20px",
    borderRadius: "5px",
    backgroundColor: "white",
    boxShadow: "0 0 5px rgba(0, 0, 0, 0.1)",
  },
  formGroup: {
    marginBottom: "10px",
  },
  formGroupLabel: {
    display: "block",
    marginBottom: "5px",
    fontWeight: "bold",
    color: "#495057",
    fontSize: "0.9em",
  },
  formGroupInput: {
    width: "100%",
    padding: "8px",
    border: "1px solid #ced4da",
    borderRadius: "4px",
    boxSizing: "border-box",
    fontSize: "14px",
    color: "#495057",
    backgroundColor: "#f8f9fa",
  },
  buttonGroup: {
    marginTop: "10px",
  },
  button: {
    padding: "10px 15px",
    marginRight: "10px",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
    backgroundColor: "#007bff",
    color: "white",
    fontSize: "14px",
  },
  discountCodesTable: {
    width: "100%",
    borderCollapse: "collapse",
    marginTop: "15px",
  },
  discountCodesTableTh: {
    border: "1px solid #ddd",
    padding: "8px",
    textAlign: "left",
    backgroundColor: "#e9ecef",
    fontWeight: "bold",
  },
  discountCodesTableTd: {
    border: "1px solid #ddd",
    padding: "8px",
    textAlign: "left",
  },
};

// In-memory storage (replace with a database in a real application)
let discountCodesData = [
  {
    code: "SUMMER20",
    percentage: 20,
    quantity: 10,
    startDate: "2024-01-01",
    endDate: "2024-12-31",
  },
];

const KhuyenMaiPage = () => {
  const [isSidebarHidden, setIsSidebarHidden] = useState(false);
  const sidebarRef = useRef<HTMLElement | null>(null);
  const mainContentRef = useRef<HTMLElement | null>(null);

  const [mostActiveUsers, setMostActiveUsers] = useState([
    { id: 1, name: "John Doe", orders: 15 },
    { id: 2, name: "Jane Smith", orders: 12 },
    { id: 3, name: "Peter Jones", orders: 10 },
  ]);

  // Discount Code Data and State
  const [discountCode, setDiscountCode] = useState("");
  const [discountPercentage, setDiscountPercentage] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [discountCodes, setDiscountCodes] = useState(discountCodesData);

  // Use useCallback to memoize the toggleSidebar function
  const toggleSidebar = useCallback(() => {
    setIsSidebarHidden((prevState) => !prevState);
  }, []);

  // Use useCallback to memoize the updateClasses function
  const updateClasses = useCallback(() => {
    const sidebar = sidebarRef.current;
    const mainContent = mainContentRef.current;

    if (sidebar && mainContent) {
      if (isSidebarHidden) {
        // sidebar.classList.add(styles.hidden);
        // mainContent.classList.add(styles.expanded);
      } else {
        // sidebar.classList.remove(styles.hidden);
        // mainContent.classList.remove(styles.expanded);
      }
    }
  }, [isSidebarHidden]);

  useEffect(() => {
    updateClasses();
  }, [isSidebarHidden, updateClasses]); // Include updateClasses as dependency

  const handleCreateDiscount = async () => {
    try {
      const response = await fetch("/api/discountCodes", {
        // Call Node.js backend
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          code: discountCode,
          percentage: discountPercentage,
          quantity: quantity,
          startDate: startDate,
          endDate: endDate,
        }),
      });

      if (response.ok) {
        // Refresh the discount code list (e.g., re-fetch or update state)
        const newDiscount = await response.json();
        setDiscountCodes([...discountCodes, newDiscount]); // Update local state
        // Clear input fields after create
        setDiscountCode("");
        setDiscountPercentage(0);
        setQuantity(1);
        setStartDate("");
        setEndDate("");

        console.log("Discount code created successfully");
      } else {
        console.error("Error creating discount code:", response.status);
      }
    } catch (error) {
      console.error("Error creating discount code:", error);
    }
  };

  const handleCancelDiscount = async (code: string) => {
    try {
      const response = await fetch(`/api/discountCodes/${code}`, {
        // Delete endpoint in Node.js
        method: "DELETE",
      });

      if (response.ok) {
        setDiscountCodes(discountCodes.filter((dc) => dc.code !== code)); // Update state after delete
        console.log("Discount code canceled successfully");
      } else {
        console.error("Error canceling discount code:", response.status);
      }
    } catch (error) {
      console.error("Error canceling discount code:", error);
    }
  };

  return (
    <>
      <Head>
        <link
          rel="stylesheet"
          href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.2/css/all.min.css"
          integrity="sha512-SnH5WK+bZxgPHs44uWIX+LLJAJ9/2PkPKZ5QiAj6Ta86w+fsb2TkcmfRyVX3pBnMFcV7oQPJkl9QevSCWr3W6A=="
          crossOrigin="anonymous"
          referrerPolicy="no-referrer"
        />
      </Head>
      <header >
        <div >
          <button  onClick={toggleSidebar}>
            ☰
          </button>

          <div >
            <Image src="/QR.png" alt="Logo" width={40} height={40} />
          </div>
          <div >SHOP</div>
        </div>

        <div >
          <a href="">
            <i className="fas fa-sign-out-alt"></i>
          </a>
        </div>
      </header>

      <div style={styles.container}>
        <aside
          id="sidebar"

          ref={sidebarRef}
        >
          <button >
            <i className=""></i>
            <Link href="" >
              Bảng Điều Khiển
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="" >
              Sản Phẩm
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="" >
              Danh Mục Sản Phẩm
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="#" >
              Tổng Danh Thu
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="" >
              Khách Hàng
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="" >
              Nhân Viên
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="#" >
              Đánh Giá
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="#" >
              Đơn Hàng
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="#" >
              Bài Viết
            </Link>
          </button>
          <button >
            <i className=""></i>
            <Link href="" >
              Khuyến Mãi
            </Link>
          </button>
        </aside>

        <main
          id="main-content"
          style={styles.mainContent}
          ref={mainContentRef}
        >
          {/* Most Active Users Section */}
          <section style={styles.activeUsersSection}>
            <h2 style={styles.sectionTitle}>Most Active Users</h2>
            <table style={styles.activeUsersTable}>
              <thead>
                <tr>
                  <th style={styles.activeUsersTableTh}>ID</th>
                  <th style={styles.activeUsersTableTh}>Name</th>
                  <th style={styles.activeUsersTableTh}>Orders</th>
                </tr>
              </thead>
              <tbody>
                {mostActiveUsers.map((user) => (
                  <tr key={user.id}>
                    <td style={styles.activeUsersTableTd}>{user.id}</td>
                    <td style={styles.activeUsersTableTd}>{user.name}</td>
                    <td style={styles.activeUsersTableTd}>{user.orders}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>

          {/* Discount Code Creation Section */}
          <section style={styles.discountCodeSection}>
            <h2 style={styles.sectionTitle}>Tạo Mã Giảm Giá</h2> {/* Vietnamese Translation */}
            <div style={styles.formGroup}>
              <label style={styles.formGroupLabel} htmlFor="discountCode">
                Mã Giảm Giá:
              </label>{" "}
              {/* Vietnamese Translation */}
              <input
                style={styles.formGroupInput}
                type="text"
                id="discountCode"
                value={discountCode}
                onChange={(e) => setDiscountCode(e.target.value)}
              />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.formGroupLabel} htmlFor="discountPercentage">
                Phần Trăm Giảm Giá:
              </label>{" "}
              {/* Vietnamese Translation */}
              <input
                style={styles.formGroupInput}
                type="number"
                id="discountPercentage"
                value={discountPercentage}
                onChange={(e) => setDiscountPercentage(Number(e.target.value))}
              />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.formGroupLabel} htmlFor="quantity">
                Số Lượng Mã:
              </label>{" "}
              {/* Vietnamese Translation */}
              <input
                style={styles.formGroupInput}
                type="number"
                id="quantity"
                value={quantity}
                onChange={(e) => setQuantity(Number(e.target.value))}
              />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.formGroupLabel} htmlFor="startDate">
                Ngày Bắt Đầu:
              </label>{" "}
              {/* Vietnamese Translation */}
              <input
                style={styles.formGroupInput}
                type="date"
                id="startDate"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.formGroupLabel} htmlFor="endDate">
                Ngày Kết Thúc:
              </label>{" "}
              {/* Vietnamese Translation */}
              <input
                style={styles.formGroupInput}
                type="date"
                id="endDate"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
            <div style={styles.buttonGroup}>
              <button style={styles.button} onClick={handleCreateDiscount}>
                Tạo
              </button>{" "}
              {/* Vietnamese Translation */}
            </div>
          </section>

          {/* Existing Discount Codes (Table Format) */}
          <section style={styles.existingDiscountsSection}>
            <h2 style={styles.sectionTitle}>Danh Sách Mã Giảm Giá</h2>{" "}
            {/* Vietnamese Translation */}
            <table style={styles.discountCodesTable}>
              <thead>
                <tr>
                  <th style={styles.discountCodesTableTh}>Mã Giảm Giá</th>{" "}
                  {/* Vietnamese Translation */}
                  <th style={styles.discountCodesTableTh}>Phần Trăm</th>{" "}
                  {/* Vietnamese Translation */}
                  <th style={styles.discountCodesTableTh}>Số Lượng</th>{" "}
                  {/* Vietnamese Translation */}
                  <th style={styles.discountCodesTableTh}>Ngày Bắt Đầu</th>{" "}
                  {/* Vietnamese Translation */}
                  <th style={styles.discountCodesTableTh}>Ngày Kết Thúc</th>{" "}
                  {/* Vietnamese Translation */}
                  <th style={styles.discountCodesTableTh}>Hành Động</th>{" "}
                  {/* Vietnamese Translation */}
                </tr>
              </thead>
              <tbody>
                {discountCodes.map((discount) => (
                  <tr key={discount.code}>
                    <td style={styles.discountCodesTableTd}>{discount.code}</td>
                    <td style={styles.discountCodesTableTd}>
                      {discount.percentage}%
                    </td>
                    <td style={styles.discountCodesTableTd}>{discount.quantity}</td>
                    <td style={styles.discountCodesTableTd}>{discount.startDate}</td>
                    <td style={styles.discountCodesTableTd}>{discount.endDate}</td>
                    <td style={styles.discountCodesTableTd}>
                      <button style={styles.button} onClick={() => handleCancelDiscount(discount.code)}>
                        Hủy
                      </button>{" "}
                      {/* Vietnamese Translation */}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>
        </main>
      </div>
    </>
  );
};

export default KhuyenMaiPage;

// --- API ROUTES ---
export async function getServerSideProps(context: any) {
  if (context.req.method === "POST") {
    const { code, percentage, quantity, startDate, endDate } = context.req.body;

    if (!code || !percentage || !quantity || !startDate || !endDate) {
      return { props: {} }; // Or handle error
    }

    const newDiscountCode = {
      code: code,
      percentage: Number(percentage),
      quantity: Number(quantity),
      startDate: startDate,
      endDate: endDate,
    };
    discountCodesData.push(newDiscountCode); // Add to our "database"
  }

  return {
    props: {}, // This runs every time
  };
}